     7→// ─── Regex patterns for task param validation ────────────────────────────────
     8→export const X_POST_URL_RE = /^https?:\/\/(x\.com|twitter\.com)\/\w+\/status\/\d+/i;
     9→export const X_USERNAME_RE = /^@?[\w]{1,15}$/;
    10→export const DISCORD_INVITE_RE = /^https?:\/\/(discord\.gg|discord\.com\/invite)\/[\w-]+$/i;
    11→export const TELEGRAM_CHANNEL_RE = /^(@[\w]{5,32}|https?:\/\/t\.me\/[\w]+)$/i;
    12→
    13→/** Validate task params based on platform + actionType. Returns error string or null. */
    14→export function validateTaskParams(task: QuestTask): string | null {
    15→    const p = task.params;
    16→    switch (task.actionType) {
    17→        case 'follow_account':
    18→            if (!p.username || !X_USERNAME_RE.test(p.username))
    19→                return `Task "${task.label}": invalid X username "${p.username || ''}"`;
    20→            break;
    21→        case 'like_post':
    22→        case 'repost':
    23→        case 'quote_post':
    24→            if (!p.postUrl || !X_POST_URL_RE.test(p.postUrl))
    25→                return `Task "${task.label}": invalid X post URL "${p.postUrl || ''}"`;
    26→            break;
    27→        case 'post':
    28→            if (!p.content || p.content.length > 280)
    29→                return `Task "${task.label}": post content required (max 280 chars)`;
    30→            break;
    31→        case 'join_server':
    32→            if (!p.inviteUrl || !DISCORD_INVITE_RE.test(p.inviteUrl))
    33→                return `Task "${task.label}": invalid Discord invite URL "${p.inviteUrl || ''}"`;
    34→            break;
    35→        case 'verify_role':
    36→            if (!p.inviteUrl || !DISCORD_INVITE_RE.test(p.inviteUrl))
    37→                return `Task "${task.label}": invalid Discord invite URL "${p.inviteUrl || ''}"`;
    38→            if (!p.roleName)
    39→                return `Task "${task.label}": role name is required`;
    40→            break;
    41→        case 'join_channel':
    42→            if (!p.channelUrl || !TELEGRAM_CHANNEL_RE.test(p.channelUrl))
    43→                return `Task "${task.label}": invalid Telegram channel "${p.channelUrl || ''}"`;
    44→            break;
    45→        default:
    46→            return `Task "${task.label}": unknown action type "${task.actionType}"`;
    47→    }
    48→    return null;
    49→}
    50→
    51→/** Validate all tasks in an array. Returns first error or null. */
    52→export function validateAllTasks(tasks: QuestTask[]): string | null {
    53→    for (const task of tasks) {
    54→        const err = validateTaskParams(task);
    55→        if (err) return err;
    56→    }
    57→    return null;
    58→}
