   401→        throw new QuestValidationError('Participation not found for this quest');
   402→    }
   403→    if (participation.status !== 'submitted') {
   404→        throw new QuestValidationError(`Can only verify submitted proofs (current: ${participation.status})`);
   405→    }
   406→
   407→    const newStatus = action === 'approve' ? 'verified' : 'rejected';
   408→    const proofData = (participation.proof as any) ?? {};
   409→    const updatedProof = action === 'reject'
   410→        ? { ...proofData, rejectionReason: reason }
   411→        : proofData;
   412→
   413→    return prisma.questParticipation.update({
   414→        where: { id: participationId },
