   422→/** Approve or reject multiple participations at once. */
   423→export async function bulkVerifyParticipations(
   424→    prisma: PrismaClient,
   425→    questId: string,
   426→    items: Array<{ participationId: string; action: 'approve' | 'reject'; reason?: string }>,
   427→) {
   428→    // Load all participations in one query
   429→    const ids = items.map(i => i.participationId);
   430→    const participations = await prisma.questParticipation.findMany({
   431→        where: { id: { in: ids }, questId },
   432→    });
   433→    const pMap = new Map(participations.map(p => [p.id, p]));
   434→
   435→    const errors: string[] = [];
   436→    const operations: any[] = [];
   437→
   438→    for (const item of items) {
   439→        const p = pMap.get(item.participationId);
   440→        if (!p) {
   441→            errors.push(`${item.participationId}: not found`);
   442→            continue;
   443→        }
   444→        if (p.status !== 'submitted') {
   445→            errors.push(`${item.participationId}: status is ${p.status}, expected submitted`);
   446→            continue;
   447→        }
   448→
   449→        const newStatus = item.action === 'approve' ? 'verified' : 'rejected';
   450→        const proofData = (p.proof as any) ?? {};
   451→        const updatedProof = item.action === 'reject'
   452→            ? { ...proofData, rejectionReason: item.reason }
   453→            : proofData;
   454→
   455→        operations.push(
   456→            prisma.questParticipation.update({
   457→                where: { id: item.participationId },
   458→                data: { status: newStatus, proof: updatedProof },
   459→            })
   460→        );
   461→    }
   462→
   463→    if (operations.length > 0) {
   464→        await prisma.$transaction(operations);
   465→    }
   466→
   467→    return { updated: operations.length, errors };
   468→}
